// Inline if/else ladder inside describe() — refactor target.
export function describe(n: number): string {
  let label: string;
  if (n < 0) {
    label = "negative";
  } else if (n === 0) {
    label = "zero";
  } else if (n < 10) {
    label = "small";
  } else if (n < 100) {
    label = "medium";
  } else {
    label = "large";
  }
  return `${n} is ${label}`;
}

